package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

import org.junit.jupiter.api.Test;

import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

public class CSVFormatTest {

    @Test
    public void testGetTrailingDelimiter() throws Exception {
        // Create CSVFormat instance
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // Use reflection to access the private field trailingDelimiter
        boolean expected = true;
        boolean actual = false;
        try {
            Method method = CSVFormat.class.getDeclaredMethod("getTrailingDelimiter");
            method.setAccessible(true);
            actual = (boolean) method.invoke(csvFormat);
        } catch (NoSuchMethodException | IllegalAccessException | InvocationTargetException e) {
            e.printStackTrace();
        }

        assertEquals(expected, actual);
    }
}
